var text = "[{\\"company\\":\\"Benjamin Hincker\\",\\"type\\":\\"photographe\\",\\"quartier\\":\\"Strasbourg\\",\\"instagram\\":\\"ben_photo\\",\\"website\\":\\"https://ben.co},{\\"company\\":\\"Jade et Lisa\\",\\"type\\":\\"boutique\\",\\"quartier\\":\\"Rouen\\",\\"instagram\\":\\"jadeetlisa\\",\\"website\\":\\"https://jadeetlisa.fr\\",\\"email\\":null,\\"phone\\":\\"0232109540\\"}]";
var objects = [];
var depth = 0, start = -1, inStr = false, esc = false;
for \(var i = 0; i < text.length; i++\) {
  var ch = text[i];
  if \(esc\) { esc = false; continue; }
  if \(ch === "\\\\"\) { esc = true; continue; }
  if \(ch === "\\""\) { inStr = !inStr; continue; }
  if \(inStr\) continue;
  if \(ch === "{"\) { if \(depth === 0\) start = i; depth++; }
  else if \(ch === "}"\) { depth--; if \(depth === 0 && start >= 0\) { var s = text.substring\(start, i+1\); try { var o = JSON.parse\(s\); if \(o.company\) objects.push\(o\); } catch\(e\) {} start = -1; } }
}
console.log\("Found:", objects.length, objects.map\(function\(o\){return o.company}\)\);
')

